import * as t from "io-ts";
import { PaymentIntent } from "./paymentIntent";

/**
 * @title MMI Sign Transaction Intent
 */
export const MmiSignTransactionIntent = t.intersection([
  PaymentIntent,
  t.type({
    custodianTransactionId: t.string,
  }),
]);

export type MmiSignTransactionIntent = t.TypeOf<
  typeof MmiSignTransactionIntent
>;
